const newTask = 'Test authentication flow';
cy.get('[data-cy="task-input"]').type(newTask);
cy.get('[data-cy="add-button"]').click();
cy.get('[data-cy="task-item"]').last().within(() => {
  cy.get('[data-cy="task-title"]').should('contain', newTask);
});
cy.get('[data-cy="task-input"]').should('have.value', '');

// Marca primeira tarefa como concluída
cy.get('[data-cy="task-item"]').first().within(() => {
  cy.get('[data-cy="task-checkbox"]').check();
});
// Clica "Clear completed"
cy.get('[data-cy="clear-completed"]').click();
// Verifica que não há mais tarefas concluídas
cy.get('[data-cy="task-item"]').should('not.have.class', 'completed');

const newTask = 'Task via Enter key';
cy.get('[data-cy="task-input"]').type(`${newTask}{enter}`);
cy.get('[data-cy="task-item"]').last().within(() => {
  cy.get('[data-cy="task-title"]').should('contain', newTask);
});

// Verifica contador inicial
cy.get('[data-cy="remaining-count"]').should('exist');
// Marca uma como concluída
cy.get('[data-cy="task-item"]').first().within(() => {
  cy.get('[data-cy="task-checkbox"]').check();
});
// Verifica que contador mudou
cy.get('[data-cy="remaining-count"]').should('contain', '1');
